module TopModule (input logic clk, input logic areset, input logic in, output logic out); localparam STATE_A = 1'b0, STATE_B = 1'b1; reg state; initial state = STATE_B; always @(posedge clk or posedge areset) begin if (areset) state <= STATE_B; else case (state) STATE_A: state <= in ? STATE_A : STATE_B; STATE_B: state <= in ? STATE_B : STATE_A; endcase end always @(*) out = (state == STATE_A); endmodule